const inr = n => new Intl.NumberFormat("en-IN",{style:"currency",currency:"INR",maximumFractionDigits:0}).format(n);
const todayStr = () => new Date().toISOString().split("T")[0];
const csvCell = value => `"${String(value ?? "").replace(/"/g,'""')}"`;
const downloadCsv = (filename, rows) => {
  if(!rows?.length)return alert("No data available for selected date range");
  const headers=Object.keys(rows[0]);
  const csv=[headers.join(","),...rows.map(row=>headers.map(key=>csvCell(row[key])).join(","))].join("\n");
  const blob=new Blob([`\uFEFF${csv}`],{type:"text/csv;charset=utf-8;"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");
  a.href=url;
  a.download=filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
};
const inDateRange = (date, from, to) => {
  const d=String(date||"").slice(0,10);
  if(!d)return false;
  return (!from||d>=from)&&(!to||d<=to);
};
const smName = (id, salesmen=SALESMEN) => salesmen.find(s=>s.id===id)?.name||"";
const smColor = (id, salesmen=SALESMEN) => salesmen.find(s=>s.id===id)?.color||"#64748b";
const leadSortTime = lead => {
  const raw=lead.assignedAt||lead.reassignedAt||lead.updatedAt||lead.createdAt||lead.updated||lead.created||"";
  const parsed=Date.parse(raw);
  if(!Number.isNaN(parsed))return parsed;
  const idNum=Number(String(lead.id||"").replace(/\D/g,""));
  return idNum||0;
};
const sortLeadsNewest = list => [...list].sort((a,b)=>leadSortTime(b)-leadSortTime(a));
const normalizeMobile = mobile => String(mobile||"").replace(/\D/g,"");
const validateMobile = mobile => {
  const raw=String(mobile||"").trim();
  if(!raw)return "Mobile number is mandatory";
  if(!/^\d+$/.test(raw))return "Mobile number must contain only numbers";
  if(raw.length!==10)return "Mobile number must be exactly 10 digits";
  return "";
};
const validateEmail = email => {
  const raw=String(email||"").trim();
  if(!raw)return "";
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(raw)?"":"Enter a valid email address";
};
const validateSalesmanEmail = email => {
  const raw=String(email||"").trim().toLowerCase();
  if(!raw)return "Email address is required";
  if(!/^[a-z0-9._%+-]+@(gmail\.com|smartcovering\.in)$/.test(raw))return "Enter a valid email like name@gmail.com or name@smartcovering.in";
  return "";
};
const validatePersonName = name => {
  const raw=String(name||"").trim();
  if(!raw)return "Salesman name is required";
  if(raw.length<2)return "Salesman name must be at least 2 characters";
  if(!/^[A-Za-z][A-Za-z .'-]*$/.test(raw))return "Salesman name should contain only letters and spaces";
  return "";
};
const customerDuplicate = ({ leads=[], orders=[], partners=[], mobile="", email="", orderRef="", excludeLeadId="", excludeOrderId="", excludePartnerId="", excludeRequestId="" }) => {
  const m=normalizeMobile(mobile);
  const e=String(email||"").trim().toLowerCase();
  if(m){
    const lead=leads.find(l=>l.id!==excludeLeadId&&normalizeMobile(l.mobile)===m);
    if(lead)return {type:"Lead", ref:lead.id, name:lead.name};
    const order=orders.find(o=>o.id!==excludeOrderId&&normalizeMobile(o.mobile)===m);
    if(order)return {type:"Order", ref:order.id, name:order.customer};
    const partner=partners.find(p=>p.id!==excludePartnerId&&normalizeMobile(p.mobile)===m);
    if(partner)return {type:"Channel Partner", ref:partner.id, name:partner.name};
    const request=partners.flatMap(p=>(p.requests||[]).map(r=>({...r,partnerName:p.name}))).find(r=>r.id!==excludeRequestId&&normalizeMobile(r.mobile)===m&&["Pending","Pending Management Approval"].includes(r.approval||r.status));
    if(request)return {type:"Order Request", ref:request.id, name:request.customer};
  }
  if(e){
    const lead=leads.find(l=>l.id!==excludeLeadId&&String(l.email||"").trim().toLowerCase()===e);
    if(lead)return {type:"Lead", ref:lead.id, name:lead.name};
  }
  if(orderRef){
    const order=orders.find(o=>o.id!==excludeOrderId&&o.id===orderRef);
    if(order)return {type:"Order", ref:order.id, name:order.customer};
  }
  return null;
};
const duplicateMsg = d => `Customer already exists in ${d.type} ${d.ref}${d.name?` (${d.name})`:""}`;
const dedupeOrders = list => {
  const seen=new Set();
  return (Array.isArray(list)?list:[]).filter(order=>{
    const key=order.leadId ? `lead:${order.leadId}` : `mobile:${normalizeMobile(order.mobile)}:${order.customer||""}`;
    if(seen.has(key))return false;
    seen.add(key);
    return true;
  });
};
const auditLog = entry => {
  try {
    const key="smartcovering_audit_logs";
    const logs=JSON.parse(localStorage.getItem(key)||"[]");
    logs.unshift({...entry,at:new Date().toISOString()});
    localStorage.setItem(key,JSON.stringify(logs.slice(0,300)));
  } catch {}
};
const duplicateAudit = (source, detail, data={}) => auditLog({event:"Duplicate Attempt",source,detail,data});
const onceKeyActive = key => {
  try {
    const storeKey="smartcovering_idempotency_keys";
    const now=Date.now();
    const keys=JSON.parse(localStorage.getItem(storeKey)||"{}");
    Object.keys(keys).forEach(k=>{ if(now-keys[k]>15000)delete keys[k]; });
    if(keys[key])return true;
    keys[key]=now;
    localStorage.setItem(storeKey,JSON.stringify(keys));
  } catch {}
  return false;
};
const leadFollowupReason = lead => {
  if(lead.status==="Rejected")return "";
  if(lead.paymentOrderId&&Number(lead.paymentBalance||0)<=0)return "";
  if(lead.status==="Converted"&&Number(lead.paymentBalance||0)<=0&&Number(lead.paymentPaid||0)>0)return "";
  if(lead.followupReason)return lead.followupReason;
  const quote=lead.quotation;
  const quoteAmount=Number(quote?.amount||0);
  const paid=Number(lead.paymentPaid||0);
  const balance=lead.paymentBalance!==undefined?Number(lead.paymentBalance||0):quoteAmount-paid;
  const pending=Math.max(balance,0);
  if(quote&&!lead.paymentMarked&&!lead.paymentOrderId)return "Quotation Approval Pending";
  if(quote&&pending>0)return paid>0?"Payment Pending":"Advance Payment Pending";
  if(lead.measurement&&!quote)return "Measurement Done but Order Not Closed";
  if((lead.svDone||lead.status==="Site Visit Scheduled")&&!lead.measurement)return "Measurement Pending";
  if(lead.contactDone||lead.status==="Contacted")return "Customer Follow-up Pending";
  return "";
};
const unifiedFollowups = (leads=[], followups=[], salesmen=SALESMEN) => {
  const getLead=id=>leads.find(l=>l.id===id);
  const lastFollowFor=leadId=>[...followups].filter(f=>f.leadId===leadId).sort((a,b)=>(b.date||"").localeCompare(a.date||""))[0];
  const autoList=leads.map(lead=>{
    const reason=leadFollowupReason(lead);
    if(!reason)return null;
    const last=lastFollowFor(lead.id);
    const quoteAmount=Number(lead.quotation?.amount||0);
    const paid=Number(lead.paymentPaid||0);
    const recognized=!!lead.paymentOrderId;
    return {
      id:`AUTO-${lead.id}`, auto:true, leadId:lead.id, smId:lead.salesman,
      customer:lead.name, mobile:lead.mobile, project:lead.location||lead.product,
      source:lead.channelPartnerName?`Channel Partner - ${lead.channelPartnerName}`:(lead.source||"Salesman"),
      salesman:smName(lead.salesman,salesmen), reason, quoteAmount,
      pending:recognized?Math.max(quoteAmount-paid,0):0,
      lastDate:last?.date||lead.updated||lead.created||"",
      nextDate:last?.next||todayStr(), status:lead.status, notes:lead.notes||lead.measurement?.notes||"",
    };
  }).filter(Boolean);
  const manualList=followups.filter(f=>f.outcome!=="Completed").map(f=>{
    const lead=getLead(f.leadId);
    if(!lead)return null;
    const mappedReason=leadFollowupReason(lead);
    if(!mappedReason)return null;
    return {
      id:f.id, auto:false, leadId:f.leadId, smId:f.smId,
      customer:lead.name||"Unknown Lead", mobile:lead.mobile||"",
      project:lead.location||lead.product||f.action||"",
      source:lead.channelPartnerName?`Channel Partner - ${lead.channelPartnerName}`:(lead.source||"Salesman"),
      salesman:smName(f.smId,salesmen),
      reason:mappedReason,
      quoteAmount:Number(lead.quotation?.amount||0),
      pending:lead.paymentOrderId?Math.max(Number(lead.paymentBalance ?? (Number(lead.quotation?.amount||0)-Number(lead.paymentPaid||0))),0):0,
      lastDate:f.date, nextDate:f.next||f.date, status:f.outcome, notes:f.notes||"",
    };
  }).filter(Boolean);
  return [...autoList,...manualList].reduce((acc,item)=>{
    const existing=acc.find(x=>x.leadId===item.leadId);
    if(!existing){ acc.push(item); return acc; }
    if(item.auto)return acc;
    existing.lastDate=item.lastDate||existing.lastDate;
    existing.nextDate=item.nextDate||existing.nextDate;
    existing.notes=item.notes||existing.notes;
    existing.manualFollowupId=item.id;
    return acc;
  },[]);
};

